import React, { useState, useEffect } from "react";
import Filters from "Filters.js";
import Results from "./components/Results";
import "./styles.css";

const App = () => {
  const [data, setData] = useState([]);
  const [filteredData, setFilteredData] = useState([]);
  const [yearRange, setYearRange] = useState([2011, 2025]);
  const [widthRange, setWidthRange] = useState([0, 100]);
  const [heightRange, setHeightRange] = useState([0, 100]);

  useEffect(() => {
    // Fetch data
    const fetchData = async () => {
      try {
        const response = await fetch("/Yung_Jake_Archive.json");
        if (!response.ok) throw new Error("Failed to fetch data");
        const json = await response.json();
        setData(json);
        setFilteredData(json);
      } catch (error) {
        console.error(error);
      }
    };
    fetchData();
  }, []);

  const filterData = () => {
    const filtered = data.filter(item => {
      const year = item.Year;
      const withinYearRange = year >= yearRange[0] && year <= yearRange[1];

      const dimensions = item["Dimensions (inches)"] || item["Dimensions (cm)"];
      if (dimensions) {
        const [width, height] = dimensions.split("x").map(Number);
        const withinWidth = width >= widthRange[0] && width <= widthRange[1];
        const withinHeight = height >= heightRange[0] && height <= heightRange[1];
        return withinYearRange && withinWidth && withinHeight;
      }

      return withinYearRange;
    });
    setFilteredData(filtered);
  };

  return (
      <div className="app">
        <header>
          <h1>Yung Jake Archive</h1>
        </header>
        <main>
          <Filters
              yearRange={yearRange}
              setYearRange={setYearRange}
              widthRange={widthRange}
              setWidthRange={setWidthRange}
              heightRange={heightRange}
              setHeightRange={setHeightRange}
              filterData={filterData}
          />
          <Results data={filteredData} />
        </main>
      </div>
  );
};

export default App;
